#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int mySqrt(int x) {
        if (x < 2) return x;
        int left = 1, right = x / 2;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            long long num = (long long)mid * mid;
            if (num == x) return mid;
            else if (num < x) left = mid + 1;
            else right = mid - 1;
        }
        return right;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int x;
    if (!(cin >> x)) return 0;
    Solution sol;
    int ans = sol.mySqrt(x);
    cout << ans << "\n";
    return 0;
}
